import{_ as a,c as e,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"账号迁移: 备份/热迁移 | Antigravity Manager","description":"学习 Antigravity Manager 的账号备份与迁移。支持 JSON 导入导出、从 Antigravity/IDE 热迁移、从 V1 数据目录迁移，并自动同步当前登录账号。","frontmatter":{"title":"账号迁移: 备份/热迁移 | Antigravity Manager","sidebarTitle":"3 分钟迁移账号池","subtitle":"账号迁移: 备份/热迁移","description":"学习 Antigravity Manager 的账号备份与迁移。支持 JSON 导入导出、从 Antigravity/IDE 热迁移、从 V1 数据目录迁移，并自动同步当前登录账号。","tags":["账号管理","备份","迁移","导入导出","state.vscdb"],"prerequisite":["start-add-account","start-first-run-data"],"duration":12,"order":5},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"}'),r={name:"zh/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"};function o(n,t,l,d,c,h){return s(),e("div",null,[...t[0]||(t[0]=[i(`<h1 id="账号备份与迁移-导入-导出、v1-db-热迁移" tabindex="-1">账号备份与迁移：导入/导出、V1/DB 热迁移 <a class="header-anchor" href="#账号备份与迁移-导入-导出、v1-db-热迁移" aria-label="Permalink to &quot;账号备份与迁移：导入/导出、V1/DB 热迁移&quot;">​</a></h1><p>你真正想“备份”的，其实不是配额数字，而是能让账号重新登录的 <code>refresh_token</code>。这节课把 Antigravity Tools 的几种迁移手段讲清楚：导入/导出 JSON、从 <code>state.vscdb</code> 导入、从 V1 数据目录导入，以及自动同步的工作方式。</p><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>把账号池导出成一个 JSON 文件（只包含 email + refresh_token）</li><li>在新机器上导入这个 JSON，快速恢复账号池</li><li>直接从 Antigravity/IDE 的 <code>state.vscdb</code> 导入“当前登录账号”（支持默认路径与自定义路径）</li><li>从 V1 数据目录自动扫描并导入旧账号</li><li>了解“自动同步当前账号”到底会做什么、什么时候会跳过</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><ul><li>重装系统/换电脑后，账号池要重新加一遍，成本很高</li><li>你在 Antigravity/IDE 里换了登录账号，但 Manager 里的“当前账号”没跟着变</li><li>你以前用过 V1/脚本版，手里只有旧数据文件，不知道能不能直接迁移</li></ul><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><ul><li>你要把账号池搬到另一台机器（桌面端/服务器/容器）</li><li>你把 Antigravity 作为“权威登录入口”，希望 Manager 自动同步当前账号</li><li>你要从旧版本（V1 数据目录）把账号迁过来</li></ul><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><ul><li>你已经能打开 Antigravity Tools，并至少有一个账号在账号池里</li><li>你知道账号数据属于敏感信息（尤其是 <code>refresh_token</code>）</li></ul><div class="warning custom-block"><p class="custom-block-title">安全提醒：把备份文件当作密码</p><p>导出的 JSON 文件包含 <code>refresh_token</code>。任何拿到它的人，都可能用它去刷新 access token。不要把备份文件上传到网盘公共链接、不要发群、不要提交到 Git。</p></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Antigravity Tools 的“迁移”本质上就两件事：</p><ol><li>找到可用的 <code>refresh_token</code></li><li>用它换取 access token，并向 Google 获取真实邮箱，然后把账号写进本地账号池</li></ol><p>它提供了三条入口：</p><ul><li>JSON 导入/导出：适合你明确要做“可控备份”</li><li>DB 导入：适合你把 Antigravity/IDE 的登录状态当作权威来源（默认找 <code>state.vscdb</code>，也支持手选文件）</li><li>V1 导入：适合从旧数据目录自动扫描并迁移</li></ul><p>另外还有一条“自动同步”：它会周期性读取 DB 里的 refresh_token，如果与 Manager 当前账号不同，就自动执行一次 DB 导入；如果相同就直接跳过（节省流量）。</p><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-导出账号池-json-备份" tabindex="-1">第 1 步：导出账号池（JSON 备份） <a class="header-anchor" href="#第-1-步-导出账号池-json-备份" aria-label="Permalink to &quot;第 1 步：导出账号池（JSON 备份）&quot;">​</a></h3><p><strong>为什么</strong> 这是最稳定、最可控的迁移方式。你拿到一个文件，就能在另一台机器恢复账号池。</p><p>操作：进入 <code>Accounts</code> 页面，点击导出按钮。</p><ul><li>如果你在设置里配置了 <code>default_export_path</code>，导出会直接写入该目录，并使用文件名 <code>antigravity_accounts_YYYY-MM-DD.json</code>。</li><li>如果没配置默认目录，会弹出系统保存对话框让你选择路径。</li></ul><p>导出文件内容大致长这样（数组里每项只保留必要字段）：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;alice@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//xxxxxxxxxxxxxxxxxxxxxxxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bob@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//yyyyyyyyyyyyyyyyyyyyyyyy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>你应该看到</strong>：页面提示导出成功，并显示保存路径。</p><h3 id="第-2-步-在新机器导入-json-恢复账号池" tabindex="-1">第 2 步：在新机器导入 JSON（恢复账号池） <a class="header-anchor" href="#第-2-步-在新机器导入-json-恢复账号池" aria-label="Permalink to &quot;第 2 步：在新机器导入 JSON（恢复账号池）&quot;">​</a></h3><p><strong>为什么</strong> 导入会逐个调用“添加账号”逻辑，用 <code>refresh_token</code> 拉取真实邮箱并写入账号池。</p><p>操作：还是在 <code>Accounts</code> 页面，点击“导入 JSON”，选择你刚导出的文件。</p><p>格式要求如下（至少需包含 1 条有效记录）：</p><ul><li>必须是 JSON 数组</li><li>系统只会导入包含 <code>refresh_token</code> 且以 <code>1//</code> 开头的条目</li></ul><p><strong>你应该看到</strong>：导入结束后，账号列表里出现导入的账号。</p><div class="tip custom-block"><p class="custom-block-title">如果你导入时 Proxy 正在运行</p><p>每次“添加账号”成功后，后端会尝试 reload 反代的 token pool，让新账号立刻生效。</p></div><h3 id="第-3-步-从-state-vscdb-导入-当前登录账号" tabindex="-1">第 3 步：从 <code>state.vscdb</code> 导入“当前登录账号” <a class="header-anchor" href="#第-3-步-从-state-vscdb-导入-当前登录账号" aria-label="Permalink to &quot;第 3 步：从 \`state.vscdb\` 导入“当前登录账号”&quot;">​</a></h3><p><strong>为什么</strong> 有时候你不想维护备份文件，只想“以 Antigravity/IDE 的登录状态为准”。DB 导入就是为这个场景准备的。</p><p>操作：进入 <code>Accounts</code> 页面，点击 <strong>Add Account</strong>，切到 <code>Import</code> 标签页：</p><ul><li>点“从数据库导入”（使用默认 DB 路径）</li><li>或点“Custom DB (state.vscdb)”手动选择一个 <code>*.vscdb</code> 文件</li></ul><p>默认 DB 路径是跨平台的（也会优先识别 <code>--user-data-dir</code> 或 portable mode）：</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-BE0kC" id="tab-djaYGb_" checked><label data-title="macOS" for="tab-djaYGb_">macOS</label><input type="radio" name="group-BE0kC" id="tab-0KtoM8L"><label data-title="Windows" for="tab-0KtoM8L">Windows</label><input type="radio" name="group-BE0kC" id="tab-f_V90VW"><label data-title="Linux" for="tab-f_V90VW">Linux</label></div><div class="blocks"><div class="language-text vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Application Support/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%APPDATA%\\Antigravity\\User\\globalStorage\\state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div></div></div><p><strong>你应该看到</strong>：</p><ul><li>导入成功后，这个账号会被自动设置为 Manager 的“当前账号”</li><li>系统会自动触发一次配额刷新</li></ul><h3 id="第-4-步-从-v1-数据目录迁移-旧版本导入" tabindex="-1">第 4 步：从 V1 数据目录迁移（旧版本导入） <a class="header-anchor" href="#第-4-步-从-v1-数据目录迁移-旧版本导入" aria-label="Permalink to &quot;第 4 步：从 V1 数据目录迁移（旧版本导入）&quot;">​</a></h3><p><strong>为什么</strong> 如果你以前用过 V1/脚本版，Manager 允许你直接扫描旧数据目录并尝试导入。</p><p>操作：在 <code>Import</code> 标签页，点击“导入 V1”。</p><p>它会去你的 home 目录下找这个路径（以及其中的索引文件）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.antigravity-agent/</span></span>
<span class="line"><span>  - antigravity_accounts.json</span></span>
<span class="line"><span>  - accounts.json</span></span></code></pre></div><p><strong>你应该看到</strong>：导入完成后，账号出现在列表里；如果没找到索引文件，后端会返回错误 <code>V1 account data file not found</code>。</p><h3 id="第-5-步-可选-开启-自动同步当前账号" tabindex="-1">第 5 步（可选）：开启“自动同步当前账号” <a class="header-anchor" href="#第-5-步-可选-开启-自动同步当前账号" aria-label="Permalink to &quot;第 5 步（可选）：开启“自动同步当前账号”&quot;">​</a></h3><p><strong>为什么</strong> 当你在 Antigravity/IDE 里切换登录账号时，Manager 可以按固定间隔检测 DB 中的 refresh_token 是否变化，并在变化时自动导入。</p><p>操作：进入 <code>Settings</code>，开启 <code>auto_sync</code>，并设置 <code>sync_interval</code>（单位：秒）。</p><p><strong>你应该看到</strong>：开启后会立即执行一次同步；之后按间隔周期性执行。如果 DB 里的 refresh_token 与当前账号相同，会直接跳过，不会重复导入。</p><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><ul><li>你能在 <code>Accounts</code> 列表中看到导入的账号</li><li>你能看见“当前账号”已经切换到你期望的那一个（DB 导入会自动设为当前）</li><li>你把 Proxy 启动后，新导入的账号能被正常用于请求（以实际调用结果为准）</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>你可能会怎么做（❌）</th><th>推荐做法（✓）</th></tr></thead><tbody><tr><td>备份文件安全</td><td>把导出的 JSON 当普通配置文件随手发出去</td><td>把 JSON 当密码，最小化传播范围，避免公网暴露</td></tr><tr><td>JSON 导入失败</td><td>JSON 不是数组，或 refresh_token 没有 <code>1//</code> 前缀</td><td>用本项目导出的 JSON 作为模板，保持字段名与结构一致</td></tr><tr><td>DB 导入找不到数据</td><td>Antigravity 没有登录过，或 DB 里缺少 <code>jetskiStateSync.agentManagerInitState</code></td><td>先确认 Antigravity/IDE 已登录，再尝试导入；必要时用 Custom DB 选对文件</td></tr><tr><td>V1 导入后账号不可用</td><td>旧 refresh_token 失效</td><td>删除该账号后用 OAuth/新 refresh_token 重新添加（以错误提示为准）</td></tr><tr><td>auto_sync 太频繁</td><td><code>sync_interval</code> 设得很小，频繁扫描 DB</td><td>把它当作“状态跟随”，间隔设到你能接受的频率即可</td></tr></tbody></table><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>JSON 导出/导入是最可控的迁移方式：备份文件里只保留 <code>email + refresh_token</code></li><li>DB 导入适合“以 Antigravity/IDE 当前登录账号为准”，并会自动设为 Manager 当前账号</li><li>V1 导入会扫描 <code>~/.antigravity-agent</code> 并兼容多种旧格式</li><li>auto_sync 会比较 refresh_token；相同则跳过，不会重复导入</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们把“迁移后的账号池”真正用起来：<strong><a href="./../proxy-and-first-client/">启动本地反代并接入第一个客户端（/healthz + SDK 配置）</a></strong>。</p><p>你会学到：</p><ul><li>怎么启动/停止 Proxy，并用 <code>/healthz</code> 做最小验证</li><li>怎么在 SDK/客户端里配置 Base URL</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>Accounts 导出/导入 JSON（<code>save_text_file</code> / <code>read_text_file</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L458-L578" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>458-578</td></tr><tr><td>Dashboard 导出账号 JSON</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Dashboard.tsx#L113-L148" target="_blank" rel="noreferrer"><code>src/pages/Dashboard.tsx</code></a></td><td>113-148</td></tr><tr><td>Import 标签页：DB 导入 / Custom DB / V1 导入按钮</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L491-L539" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>491-539</td></tr><tr><td>添加账号：忽略前端 email、用 refresh_token 获取真实邮箱、自动刷新配额、Proxy 热 reload</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>DB 导入：从 <code>state.vscdb</code> 提取 refresh_token（ItemTable + base64 + protobuf）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/migration.rs#L192-L267" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/migration.rs</code></a></td><td>192-267</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>DB 导入后自动设为“当前账号”并刷新配额</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L495-L511" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>495-511</td></tr><tr><td>auto_sync：比较 refresh_token，相同直接跳过；变化则触发 DB 导入</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L532-L564" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>532-564</td></tr><tr><td>前端后台任务：按 <code>sync_interval</code> 周期性调用 <code>syncAccountFromDb()</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/common/BackgroundTaskRunner.tsx#L43-L72" target="_blank" rel="noreferrer"><code>src/components/common/BackgroundTaskRunner.tsx</code></a></td><td>43-72</td></tr></tbody></table></details>`,61)])])}const u=a(r,[["render",o]]);export{g as __pageData,u as default};
